from itertools import permutations

class Solution:
    def largestInteger(self, num):
        digits = list(str(num))
        even_positions = [i for i, d in enumerate(digits) if int(d) % 2 == 0]
        odd_positions = [i for i, d in enumerate(digits) if int(d) % 2 == 1]
        even_vals = [digits[i] for i in even_positions]
        odd_vals = [digits[i] for i in odd_positions]
        best_num = -1
        seen_even = set(permutations(even_vals)) if even_vals else {()}
        seen_odd = set(permutations(odd_vals)) if odd_vals else {()}
        for ep in seen_even:
            for op in seen_odd:
                candidate = list(digits)
                for pos, d in zip(even_positions, ep):
                    candidate[pos] = d
                for pos, d in zip(odd_positions, op):
                    candidate[pos] = d
                value = int(''.join(candidate))
                if value > best_num:
                    best_num = value
        return best_num

