class Solution:
    def largestInteger(self, num):
        s = str(num)
        evens = sorted((c for c in s if int(c) % 2 == 0), reverse=True)
        odds = sorted((c for c in s if int(c) % 2 == 1), reverse=True)
        ei, oi = 0, 0
        out = []
        for c in s:
            if int(c) % 2 == 0:
                out.append(evens[ei])
                ei += 1
            else:
                out.append(odds[oi])
                oi += 1
        return int(''.join(out))

