var largestInteger = function(num) {
    const s = String(num);
    const evens = s.split('').filter(c => Number(c) % 2 === 0).sort((a, b) => b - a);
    const odds = s.split('').filter(c => Number(c) % 2 === 1).sort((a, b) => b - a);
    let ei = 0, oi = 0;
    const out = [];
    for (const c of s) {
        if (Number(c) % 2 === 0) {
            out.push(evens[ei]);
            ei += 1;
        } else {
            out.push(odds[oi]);
            oi += 1;
        }
    }
    return Number(out.join(''));
};
